// 从预处理指令中提取文件名
// 格式: # linenum filename flags
void extractFilenameFromLine(const std::string& line) {
  // 匹配 # linenum "filename" 或 # linenum filename
  std::regex lineDirectiveRegex(R"(^#\s+(\d+)\s+"([^"]+)".*)");
  std::regex lineDirectiveRegex2(R"(^#\s+(\d+)\s+(\S+).*)");
  std::smatch match;

  if (std::regex_match(line, match, lineDirectiveRegex)) {
    lineOffset = std::stoi(match[1].str()) - 1;
    currentFilename = match[2].str();
  } else if (std::regex_match(line, match, lineDirectiveRegex2)) {
    lineOffset = std::stoi(match[1].str()) - 1;
    currentFilename = match[2].str();
  }
}

int
main(int argc, char* argv[])
{
  if (argc != 3) {
    std::cout << "Usage: " << argv[0] << " <input> <output>\n";
    return -1;
  }

  std::ifstream inFile(argv[1]);
  if (!inFile) {
    std::cout << "Error: unable to open input file: " << argv[1] << '\n';
    return -2;
  }

  std::ofstream outFile(argv[2]);
  if (!outFile) {
    std::cout << "Error: unable to open output file: " << argv[2] << '\n';
    return -3;
  }

  std::cout << "程序 '" << argv[0] << std::endl;
  std::cout << "输入 '" << argv[1] << std::endl;
  std::cout << "输出 '" << argv[2] << std::endl;

  // 首先读取文件内容，提取预处理指令中的文件名
  std::string line;
  std::string fileContent;
  std::ifstream preprocessFile(argv[1]);
  while (std::getline(preprocessFile, line)) {
    // 检查是否是预处理指令行
    if (line.size() > 0 && line[0] == '#') {
      extractFilenameFromLine(line);
    }
  }
  preprocessFile.close();

  // 重新打开文件进行词法分析
  inFile.clear();
  inFile.seekg(0);

  antlr4::ANTLRInputStream input(inFile);
  SYsULexer lexer(&input);

  antlr4::CommonTokenStream tokens(&lexer);
  tokens.fill();

  for (auto&& token : tokens.getTokens()) {
    print_token(token, tokens, outFile, lexer);
  }
}

